      labSheet: { experimentName: 'Study of Couplings and Clutch Models', aim: 'To identify construction and torque path of common couplings and clutches.', apparatus: ['muff coupling model', 'flange coupling model', 'clutch model', 'sketch sheet'], theory: 'Couplings transmit torque permanently; clutches transmit torque through positive engagement or friction.', procedure: ['Identify shaft, key and hub.', 'Trace torque path.', 'Note rigid/flexible features.', 'Identify clutch friction surfaces.', 'Calculate active surfaces for a sample clutch.'], observationTable: { headers: ['Model', 'Parts', 'Torque path', 'Flexibility', 'Application'], rows: 5 }, precautions: ['Do not dismantle without permission.', 'Label parts carefully.', 'Distinguish coupling and clutch functions.'], result: 'Coupling and clutch torque paths were identified and compared.' },
